'use client';

import { useState } from 'react';
import Map from '@/components/Map';
import DirectionsPanel from '@/components/DirectionsPanel';

const TABS = [
  { id: 'dashboard', label: 'Dashboard', icon: '🏠' },
  { id: 'itinerary', label: 'Itinerary', icon: '📅' },
  { id: 'guides', label: 'Guides', icon: '👨‍🏫' },
  { id: 'food', label: 'Food', icon: '🍽️' },
  { id: 'weather', label: 'Weather', icon: '🌤️' },
  { id: 'safety', label: 'Safety', icon: '🛡️' },
  { id: 'translate', label: 'Translate', icon: '🌐' },
  { id: 'map', label: 'Map', icon: '🗺️' },
  { id: 'directions', label: 'Directions', icon: '🧭' },
];

const FEATURES = [
  { icon: '🤖', title: 'Context Agent', desc: 'Learns your travel preferences and style' },
  { icon: '📅', title: 'AI Itinerary', desc: 'Generates optimised day-by-day plans' },
  { icon: '🍽️', title: 'Food Expert', desc: 'Curates authentic local cuisine picks' },
  { icon: '🌐', title: 'Translator', desc: 'Real-time language assistance' },
  { icon: '👨‍🏫', title: 'Guide Matcher', desc: 'Connects you with verified local guides' },
  { icon: '🛡️', title: 'Safety Advisor', desc: 'Emergency info & real-time safety' },
];

export default function Home() {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [journey, setJourney] = useState(null);
  const [guides, setGuides] = useState(null);
  const [loading, setLoading] = useState(false);
  const [weather, setWeather] = useState(null);
  const [translation, setTranslation] = useState(null);
  const [safetyInfo, setSafetyInfo] = useState(null);
  const [error, setError] = useState('');
  const [successMessage, setSuccessMessage] = useState('');

  const clearMessages = () => { setError(''); setSuccessMessage(''); };

  const showError = (msg) => {
    setError(msg);
    setTimeout(() => setError(''), 6000);
  };

  const showSuccess = (msg) => {
    setSuccessMessage(msg);
    setTimeout(() => setSuccessMessage(''), 5000);
  };

  const planJourney = async () => {
    clearMessages();
    setLoading(true);
    try {
      const userData = {
        userId: 'user_' + Date.now(),
        name: 'Smart Tourist',
        language: 'en',
        interests: ['cultural', 'nature', 'food', 'adventure'],
        budget: 'medium',
        travelStyle: 'balanced',
        tripDuration: 3,
        groupSize: 2,
        dietaryRestrictions: [],
      };

      const resp = await fetch('/api/agent/journey', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(userData),
      });
      const data = await resp.json();

      if (data.success) {
        setJourney(data.data);
        showSuccess('Journey planned successfully!');

        const gResp = await fetch('/api/agent/guides', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(data.data.userProfile),
        });
        const gData = await gResp.json();
        if (gData.success) setGuides(gData.data);
      } else {
        showError(data.error || 'Failed to plan journey');
      }
    } catch (e) {
      showError('Network error: ' + e.message);
    } finally {
      setLoading(false);
    }
  };

  const getWeather = async () => {
    clearMessages();
    setLoading(true);
    try {
      const resp = await fetch('/api/weather?lat=8.5241&lng=76.9366');
      const data = await resp.json();
      if (data.success) { setWeather(data.data); showSuccess('Weather data loaded!'); }
      else showError(data.error || 'Failed to fetch weather');
    } catch (e) {
      showError('Error: ' + e.message);
    } finally {
      setLoading(false);
    }
  };

  const translateText = async () => {
    clearMessages();
    setLoading(true);
    try {
      const resp = await fetch('/api/agent/translate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ text: 'Hello! I am looking for a restaurant. Can you help me?', targetLanguage: 'hi' }),
      });
      const data = await resp.json();
      if (data.success) { setTranslation(data.data); showSuccess('Translation complete!'); }
      else showError(data.error || 'Failed to translate');
    } catch (e) {
      showError('Error: ' + e.message);
    } finally {
      setLoading(false);
    }
  };

  const getSafetyInfo = async () => {
    clearMessages();
    setLoading(true);
    try {
      const resp = await fetch('/api/agent/safety?lat=8.5241&lng=76.9366&action=emergency');
      const data = await resp.json();
      if (data.success) { setSafetyInfo(data.data); showSuccess('Safety information loaded!'); }
      else showError(data.error || 'Failed to fetch safety info');
    } catch (e) {
      showError('Error: ' + e.message);
    } finally {
      setLoading(false);
    }
  };

  const switchTab = (id) => { clearMessages(); setActiveTab(id); };

  const weatherEmoji = (code) => {
    if (code === 0 || code === 1) return '☀️';
    if (code === 2 || code === 3) return '⛅';
    if (code >= 45 && code <= 48) return '🌫️';
    if (code >= 51 && code <= 67) return '🌧️';
    if (code >= 71 && code <= 77) return '❄️';
    if (code >= 80 && code <= 82) return '🌦️';
    if (code >= 95) return '⛈️';
    return '🌡️';
  };

  return (
    <div style={{ minHeight: '100vh' }}>
      {/* Toasts */}
      {error && (
        <div className="toast toast-error">
          <span>⚠️</span>
          <span>{error}</span>
        </div>
      )}
      {successMessage && (
        <div className="toast toast-success">
          <span>✅</span>
          <span>{successMessage}</span>
        </div>
      )}

      {/* ─── Header ─── */}
      <header className="header">
        <div className="header-inner">
          <div className="flex gap-3" style={{ alignItems: 'center' }}>
            <span className="animate-float" style={{ fontSize: '1.8rem' }}>🌍</span>
            <div>
              <div className="logo-mark">SmartTour</div>
              <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', marginTop: '-2px' }}>AI Travel Companion</div>
            </div>
          </div>
          <div className="flex gap-3" style={{ alignItems: 'center' }}>
            <div className="badge-ai">Agentic AI</div>
            <button
              onClick={planJourney}
              disabled={loading}
              className="btn-primary"
              style={{ padding: '9px 20px', fontSize: '0.8rem' }}
            >
              {loading ? <><span className="spinner" style={{ width: 14, height: 14 }} /> Planning...</> : '🚀 Plan Journey'}
            </button>
          </div>
        </div>
      </header>

      {/* ─── Nav Tabs ─── */}
      <nav className="nav-tabs">
        <div className="nav-tabs-inner">
          {TABS.map((tab) => (
            <button
              key={tab.id}
              onClick={() => switchTab(tab.id)}
              className={`tab-btn${activeTab === tab.id ? ' active' : ''}`}
            >
              <span>{tab.icon}</span>
              <span>{tab.label}</span>
            </button>
          ))}
        </div>
      </nav>

      {/* ─── Main Content ─── */}
      <main className="main-content">

        {/* ══════════ DASHBOARD ══════════ */}
        {activeTab === 'dashboard' && (
          <div className="animate-fade-up">
            {/* Hero */}
            <div className="hero">
              <div className="hero-eyebrow">✨ Powered by Multi-Agent AI</div>
              <h1 className="hero-title">
                Your <span className="highlight">Perfect Journey</span><br />Starts Here
              </h1>
              <p className="hero-description">
                Discover personalised itineraries, local guides, authentic cuisine,
                real-time translation and safety insights — all orchestrated by AI agents working in harmony.
              </p>
              <div className="flex gap-3" style={{ flexWrap: 'wrap' }}>
                <button
                  onClick={planJourney}
                  disabled={loading}
                  className="hero-btn"
                >
                  {loading
                    ? <><span className="spinner" style={{ width: 16, height: 16 }} /> Planning your journey...</>
                    : <><span>🚀</span> Plan My Journey</>
                  }
                </button>
                <button onClick={() => switchTab('map')} className="btn-ghost">
                  Explore Map →
                </button>
              </div>
            </div>

            {/* AI Agents */}
            <div className="mb-8">
              <h2 className="section-title">AI Agent Network</h2>
              <p className="section-subtitle">Six specialised agents working in real-time to make your travel seamless</p>
              <div className="feature-grid">
                {FEATURES.map((f, i) => (
                  <div key={i} className="feature-card">
                    <div className="feature-icon">{f.icon}</div>
                    <div className="feature-title">{f.title}</div>
                    <div className="feature-desc">{f.desc}</div>
                  </div>
                ))}
              </div>
            </div>

            {/* Journey Result */}
            {journey && (
              <div className="journey-result animate-fade-up">
                <div className="flex-between mb-6">
                  <h3 className="section-title" style={{ marginBottom: 0 }}>✨ Your Journey Plan</h3>
                  <span className="pill pill-green">Active</span>
                </div>

                <div className="stats-row">
                  <div className="stat-card">
                    <span className="stat-value">{journey.itinerary?.duration || 3}</span>
                    <span className="stat-label">Days Planned</span>
                  </div>
                  <div className="stat-card">
                    <span className="stat-value">{journey.userProfile?.adventureScore || 75}</span>
                    <span className="stat-label">Adventure Score</span>
                  </div>
                  <div className="stat-card">
                    <span className="stat-value" style={{ fontSize: '1.2rem', textTransform: 'capitalize' }}>{journey.userProfile?.travelStyle}</span>
                    <span className="stat-label">Travel Style</span>
                  </div>
                  <div className="stat-card">
                    <span className="stat-value">{journey.userProfile?.groupSize}</span>
                    <span className="stat-label">Travellers</span>
                  </div>
                </div>

                {journey.itinerary?.days && (
                  <div>
                    <h4 style={{ fontWeight: 700, color: 'var(--text-primary)', marginBottom: 16, fontSize: '1rem' }}>
                      Daily Schedule
                    </h4>
                    <div className="space-y-3">
                      {journey.itinerary.days.map((d, i) => (
                        <div key={i} className="journey-day-card">
                          <div className="flex gap-3" style={{ alignItems: 'center' }}>
                            <div style={{
                              width: 36, height: 36, borderRadius: 10, background: 'var(--gradient-accent)',
                              display: 'flex', alignItems: 'center', justifyContent: 'center',
                              fontWeight: 800, fontSize: '0.9rem', color: 'white'
                            }}>
                              {d.day}
                            </div>
                            <div>
                              <div style={{ fontWeight: 600, fontSize: '0.9rem', color: 'var(--text-primary)' }}>
                                Day {d.day} — {d.theme || 'Exploration'}
                              </div>
                              <div style={{ fontSize: '0.78rem', color: 'var(--text-muted)' }}>
                                {d.duration || '8 hours'} • {d.activities?.length || 0} activities
                              </div>
                            </div>
                          </div>
                          <div className="flex gap-2">
                            <span className="pill pill-blue">{d.activities?.length || 0} acts</span>
                            <button
                              onClick={() => switchTab('itinerary')}
                              className="btn-ghost"
                              style={{ padding: '6px 14px', fontSize: '0.78rem' }}
                            >
                              View
                            </button>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        )}

        {/* ══════════ ITINERARY ══════════ */}
        {activeTab === 'itinerary' && (
          <div className="animate-fade-up">
            <h2 className="section-title">📅 Itinerary</h2>
            <p className="section-subtitle">Your AI-generated day-by-day travel plan</p>

            {journey ? (
              <div className="space-y-4">
                {journey.itinerary?.days?.map((d, i) => (
                  <div key={i} className="card">
                    <div className="flex-between mb-4">
                      <div className="flex gap-3" style={{ alignItems: 'center' }}>
                        <div style={{
                          width: 44, height: 44, borderRadius: 12, background: 'var(--gradient-accent)',
                          display: 'flex', alignItems: 'center', justifyContent: 'center',
                          fontWeight: 800, fontSize: '1rem', color: 'white'
                        }}>
                          D{d.day}
                        </div>
                        <div>
                          <div style={{ fontWeight: 700, fontSize: '1rem', color: 'var(--text-primary)' }}>
                            Day {d.day} — {d.theme || 'Exploration'}
                          </div>
                          <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)', marginTop: 2 }}>
                            {new Date(d.date).toLocaleDateString('en-US', { weekday: 'long', month: 'short', day: 'numeric' })}
                          </div>
                        </div>
                      </div>
                      <div className="flex gap-2">
                        <span className="pill pill-green">🛡️ Safe</span>
                        <span className="pill pill-blue">⏱ {d.duration || '8h'}</span>
                        <span className="pill pill-purple">🎯 {d.activities?.length || 0} activities</span>
                      </div>
                    </div>

                    <div className="grid-3" style={{ marginBottom: 16 }}>
                      {['morning', 'afternoon', 'evening'].map((period) => {
                        const acts = d.activities?.filter(a => {
                          if (period === 'morning') return a.time?.startsWith('0') || a.time?.startsWith('05') || a.time?.startsWith('06') || a.time?.startsWith('07') || a.time?.startsWith('08');
                          if (period === 'afternoon') return a.time?.startsWith('13') || a.time?.startsWith('14');
                          return a.time?.startsWith('17') || a.time?.startsWith('19');
                        }) || [];
                        const icons = { morning: '🌅', afternoon: '☀️', evening: '🌆' };
                        return (
                          <div key={period} className="card-inner">
                            <div style={{ fontSize: '0.75rem', fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.5px', marginBottom: 10 }}>
                              {icons[period]} {period}
                            </div>
                            {acts.length > 0 ? acts.map((act, j) => (
                              <div key={j} style={{ padding: '8px 0', borderBottom: j < acts.length - 1 ? '1px solid var(--border)' : 'none' }}>
                                <div style={{ fontSize: '0.85rem', fontWeight: 600, color: 'var(--text-primary)' }}>{act.name}</div>
                                <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)', marginTop: 2 }}>
                                  {act.time} • {act.duration}h
                                </div>
                              </div>
                            )) : (
                              <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)', fontStyle: 'italic' }}>Free time</div>
                            )}
                          </div>
                        );
                      })}
                    </div>

                    <div className="card-inner">
                      <div style={{ fontSize: '0.75rem', fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.5px', marginBottom: 10 }}>
                        🍽️ Meals
                      </div>
                      <div className="flex gap-4" style={{ flexWrap: 'wrap' }}>
                        {d.meals && Object.entries(d.meals).map(([meal, desc]) => (
                          <div key={meal}>
                            <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)', textTransform: 'capitalize' }}>{meal}: </span>
                            <span style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', fontWeight: 500 }}>{desc}</span>
                          </div>
                        ))}
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="empty-state">
                <div className="empty-state-icon">📅</div>
                <div className="empty-state-title">No itinerary yet</div>
                <div className="empty-state-desc">Plan your journey first to generate a personalised day-by-day itinerary.</div>
                <button onClick={() => switchTab('dashboard')} className="btn-primary">
                  Go to Dashboard
                </button>
              </div>
            )}
          </div>
        )}

        {/* ══════════ GUIDES ══════════ */}
        {activeTab === 'guides' && (
          <div className="animate-fade-up">
            <h2 className="section-title">👨‍🏫 Recommended Guides</h2>
            <p className="section-subtitle">AI-matched local expert guides based on your preferences</p>

            {guides?.matchedGuides ? (
              <div className="grid-auto">
                {guides.matchedGuides.slice(0, 6).map((g) => (
                  <div key={g.id} className="guide-card">
                    <div className="guide-card-header">
                      <div className="guide-avatar">👨‍🏫</div>
                      <div className="guide-name">{g.name}</div>
                      <div className="guide-exp">{g.experience} years experience</div>
                    </div>
                    <div className="guide-body">
                      <div className="guide-stat-row">
                        <span className="pill pill-yellow">
                          ★ {g.rating?.toFixed(1)}
                        </span>
                        <span className="pill pill-green">
                          {g.compatibilityScore}% match
                        </span>
                      </div>

                      <div className="guide-section">
                        <div className="guide-section-label">Languages</div>
                        <div className="flex gap-2" style={{ flexWrap: 'wrap', marginTop: 4 }}>
                          {g.languages?.map((lang, i) => (
                            <span key={i} className="pill pill-blue">{lang}</span>
                          ))}
                        </div>
                      </div>

                      <div className="guide-section">
                        <div className="guide-section-label">Specialties</div>
                        <div className="flex gap-2" style={{ flexWrap: 'wrap', marginTop: 4 }}>
                          {g.specialties?.slice(0, 3).map((s, i) => (
                            <span key={i} className="pill pill-purple">{s}</span>
                          ))}
                        </div>
                      </div>

                      <div className="guide-price-row">
                        <div>
                          <span className="guide-price">₹{g.price}</span>
                          <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>/day</span>
                        </div>
                        <button className="btn-green" style={{ padding: '9px 20px', fontSize: '0.85rem' }}>
                          📞 Book Now
                        </button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="empty-state">
                <div className="empty-state-icon">👨‍🏫</div>
                <div className="empty-state-title">No guides matched yet</div>
                <div className="empty-state-desc">Plan your journey to get AI-matched guide recommendations.</div>
                <button onClick={() => switchTab('dashboard')} className="btn-primary">Plan Journey</button>
              </div>
            )}
          </div>
        )}

        {/* ══════════ FOOD ══════════ */}
        {activeTab === 'food' && (
          <div className="animate-fade-up">
            <h2 className="section-title">🍽️ Food Recommendations</h2>
            <p className="section-subtitle">Curated local cuisine picks for Kerala's finest flavours</p>

            {journey?.foodRecommendations ? (
              <div className="space-y-4">
                {journey.foodRecommendations.recommendations?.slice(0, 3).map((dayFood, i) => (
                  <div key={i} className="card">
                    <h3 style={{ fontWeight: 700, fontSize: '1rem', color: 'var(--text-primary)', marginBottom: 16 }}>
                      Day {dayFood.day} Meals
                    </h3>
                    <div className="grid-4" style={{ gap: '12px' }}>
                      {['breakfast', 'lunch', 'dinner', 'snacks'].map((meal) => {
                        const items = dayFood[meal];
                        const icons = { breakfast: '🌅', lunch: '☀️', dinner: '🌙', snacks: '🍫' };
                        const colors = { breakfast: 'pill-yellow', lunch: 'pill-green', dinner: 'pill-purple', snacks: 'pill-cyan' };
                        return (
                          <div key={meal} className="card-inner">
                            <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 12 }}>
                              <span style={{ fontSize: '1.1rem' }}>{icons[meal]}</span>
                              <span style={{ fontSize: '0.75rem', fontWeight: 700, textTransform: 'capitalize', color: 'var(--text-primary)' }}>{meal}</span>
                            </div>
                            {(Array.isArray(items) ? items : []).map((item, j) => (
                              <div key={j} style={{ padding: '8px 0', borderTop: j > 0 ? '1px solid var(--border)' : 'none' }}>
                                <div style={{ fontSize: '0.85rem', fontWeight: 600, color: 'var(--text-primary)' }}>{item.name}</div>
                                <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)', marginTop: 2, lineHeight: 1.4 }}>{item.description}</div>
                                <div style={{ display: 'flex', gap: 6, marginTop: 6 }}>
                                  <span className={`pill ${colors[meal]}`} style={{ fontSize: '0.7rem' }}>{item.price}</span>
                                  {item.vegetarian && <span className="pill pill-green" style={{ fontSize: '0.7rem' }}>Veg</span>}
                                </div>
                              </div>
                            ))}
                          </div>
                        );
                      })}
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div>
                <div className="empty-state" style={{ marginBottom: 32 }}>
                  <div className="empty-state-icon">🍽️</div>
                  <div className="empty-state-title">Plan first to get food recs</div>
                  <div className="empty-state-desc">Our Food Expert Agent will personalise options to your dietary preferences.</div>
                  <button onClick={() => switchTab('dashboard')} className="btn-primary">Plan Journey</button>
                </div>

                {/* Static popular dishes */}
                <h3 style={{ fontWeight: 700, fontSize: '1.1rem', color: 'var(--text-primary)', marginBottom: 16 }}>
                  🌟 Signature Kerala Dishes
                </h3>
                <div className="grid-auto">
                  {[
                    { name: 'Kerala Fish Curry', desc: 'Coconut-based tangy fish curry', emoji: '🐟', tag: 'Seafood', rating: 4.8 },
                    { name: 'Puttu & Kadala', desc: 'Steamed rice flour with chickpea curry', emoji: '🌾', tag: 'Vegetarian', rating: 4.6 },
                    { name: 'Kerala Sadhya', desc: 'Traditional vegetarian feast on banana leaf', emoji: '🍛', tag: 'Festive', rating: 4.9 },
                    { name: 'Appam & Stew', desc: 'Lacy rice pancakes with coconut stew', emoji: '🥞', tag: 'Breakfast', rating: 4.7 },
                    { name: 'Prawn Moilee', desc: 'Delicate prawns in yellow coconut gravy', emoji: '🦐', tag: 'Seafood', rating: 4.7 },
                    { name: 'Karimeen Pollichathu', desc: 'Pearl spot fish grilled in banana leaf', emoji: '🐠', tag: 'Traditional', rating: 4.8 },
                  ].map((dish, i) => (
                    <div key={i} className="card" style={{ display: 'flex', gap: 16, alignItems: 'flex-start' }}>
                      <div style={{ fontSize: '2rem', lineHeight: 1, flexShrink: 0 }}>{dish.emoji}</div>
                      <div>
                        <div style={{ fontWeight: 700, fontSize: '0.95rem', color: 'var(--text-primary)' }}>{dish.name}</div>
                        <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)', margin: '4px 0 8px', lineHeight: 1.4 }}>{dish.desc}</div>
                        <div style={{ display: 'flex', gap: 6 }}>
                          <span className="pill pill-green">{dish.tag}</span>
                          <span className="pill pill-yellow">★ {dish.rating}</span>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {/* ══════════ WEATHER ══════════ */}
        {activeTab === 'weather' && (
          <div className="animate-fade-up">
            <div className="flex-between mb-6" style={{ flexWrap: 'wrap', gap: 12 }}>
              <div>
                <h2 className="section-title">🌤️ Weather</h2>
                <p className="section-subtitle" style={{ marginBottom: 0 }}>Real-time forecast for Kerala, India</p>
              </div>
              <button onClick={getWeather} disabled={loading} className="btn-primary">
                {loading ? <><span className="spinner" style={{ width: 14, height: 14 }} /> Loading...</> : '🔄 Refresh Weather'}
              </button>
            </div>

            {weather ? (
              <div>
                <div className="weather-main">
                  <div className="flex-between" style={{ marginBottom: 24, flexWrap: 'wrap', gap: 16 }}>
                    <div>
                      <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)', fontWeight: 600, marginBottom: 8 }}>
                        📍 Kerala, India • {new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' })}
                      </div>
                      <div className="weather-temp">{Math.round(weather.current?.temperature || 0)}°C</div>
                      <div style={{ fontSize: '1.1rem', color: 'var(--text-secondary)', marginTop: 8 }}>
                        {weatherEmoji(weather.current?.weatherCode)} {weather.current?.description}
                      </div>
                    </div>
                    <div>
                      <div style={{ fontSize: '4rem', textAlign: 'right', lineHeight: 1 }}>
                        {weatherEmoji(weather.current?.weatherCode)}
                      </div>
                    </div>
                  </div>

                  <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 12 }}>
                    {[
                      { label: 'Feels Like', value: `${Math.round(weather.current?.apparentTemperature || 0)}°C`, icon: '🌡️' },
                      { label: 'Humidity', value: `${weather.current?.humidity || 0}%`, icon: '💧' },
                      { label: 'Wind Speed', value: `${Math.round(weather.current?.windSpeed || 0)} m/s`, icon: '💨' },
                    ].map((stat, i) => (
                      <div key={i} style={{ background: 'rgba(255,255,255,0.07)', borderRadius: 12, padding: '14px', backdropFilter: 'blur(10px)' }}>
                        <div style={{ fontSize: '0.75rem', color: 'rgba(255,255,255,0.55)', marginBottom: 6 }}>
                          {stat.icon} {stat.label}
                        </div>
                        <div style={{ fontSize: '1.4rem', fontWeight: 800, color: 'white' }}>{stat.value}</div>
                      </div>
                    ))}
                  </div>
                </div>

                {weather.daily?.length > 0 && (
                  <div className="card">
                    <h4 style={{ fontWeight: 700, color: 'var(--text-primary)', marginBottom: 16 }}>7-Day Forecast</h4>
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: 10 }}>
                      {weather.daily.map((d, i) => (
                        <div key={i} className="weather-forecast-item">
                          <div className="weather-day-label">
                            {new Date(d.date + 'T12:00:00').toLocaleDateString('en-US', { weekday: 'short' })}
                          </div>
                          <div style={{ fontSize: '1.4rem', margin: '8px 0' }}>{weatherEmoji(d.weatherCode)}</div>
                          <div className="weather-max">{Math.round(d.maxTemp)}°</div>
                          <div className="weather-min">{Math.round(d.minTemp)}°</div>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            ) : (
              <div className="empty-state">
                <div className="empty-state-icon">🌤️</div>
                <div className="empty-state-title">No weather data yet</div>
                <div className="empty-state-desc">Click the button above to load real-time weather data powered by Open-Meteo.</div>
                <button onClick={getWeather} disabled={loading} className="btn-primary">
                  {loading ? 'Loading...' : '🌤️ Load Weather'}
                </button>
              </div>
            )}
          </div>
        )}

        {/* ══════════ SAFETY ══════════ */}
        {activeTab === 'safety' && (
          <div className="animate-fade-up">
            <div className="flex-between mb-6" style={{ flexWrap: 'wrap', gap: 12 }}>
              <div>
                <h2 className="section-title">🛡️ Safety</h2>
                <p className="section-subtitle" style={{ marginBottom: 0 }}>Emergency contacts and travel safety tips</p>
              </div>
              <button onClick={getSafetyInfo} disabled={loading} className="btn-danger">
                {loading ? <><span className="spinner" style={{ width: 14, height: 14 }} /> Loading...</> : '🚨 Get Safety Info'}
              </button>
            </div>

            <div className="grid-2" style={{ gap: 24 }}>
              <div>
                <div className="card" style={{ background: 'rgba(239,68,68,0.05)', borderColor: 'rgba(239,68,68,0.25)', marginBottom: 16 }}>
                  <h3 style={{ fontWeight: 700, fontSize: '1rem', color: '#f87171', marginBottom: 20 }}>🚨 Emergency Numbers</h3>
                  <div className="emergency-grid">
                    {[
                      { service: 'Police', number: '100' },
                      { service: 'Ambulance', number: '102' },
                      { service: 'Fire', number: '101' },
                      { service: 'Disaster', number: '108' },
                      { service: "Women's Help", number: '1091' },
                      { service: 'Tourist Police', number: '1363' },
                    ].map((c, i) => (
                      <div key={i} className="emergency-card">
                        <span className="emergency-number">{c.number}</span>
                        <span className="emergency-service">{c.service}</span>
                      </div>
                    ))}
                  </div>
                </div>

                {journey?.safetyInformation?.locationAssessments && (
                  <div className="card animate-fade-up">
                    <h3 style={{ fontWeight: 700, fontSize: '1rem', color: 'var(--text-primary)', marginBottom: 16 }}>📋 Per-Location Safety Assessment</h3>
                    <div className="space-y-4">
                      {journey.safetyInformation.locationAssessments.map((assessment, i) => (
                        <div key={i} className="card-inner">
                          <div className="flex-between mb-3">
                            <div style={{ fontWeight: 700, fontSize: '0.9rem', color: 'var(--text-primary)' }}>{assessment.location}</div>
                            <span className={`pill ${assessment.safetyScore >= 80 ? 'pill-green' : 'pill-yellow'}`}>
                              Score: {assessment.safetyScore}/100
                            </span>
                          </div>
                          <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)', marginBottom: 8 }}>
                            Risk Level: <span style={{ color: 'var(--text-secondary)', fontWeight: 600 }}>{assessment.riskLevel}</span>
                          </div>
                          <div className="flex gap-2" style={{ flexWrap: 'wrap' }}>
                            {assessment.recommendations.map((rec, j) => (
                              <span key={j} className="pill pill-blue" style={{ fontSize: '0.7rem' }}>• {rec}</span>
                            ))}
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                )}

                {safetyInfo && !journey && (
                  <div className="card animate-fade-up">
                    <h3 style={{ fontWeight: 700, fontSize: '1rem', color: 'var(--text-primary)', marginBottom: 16 }}>📋 AI Safety Assessment</h3>
                    <div style={{ display: 'flex', gap: 12, marginBottom: 16, flexWrap: 'wrap' }}>
                      <span className="pill pill-green">✅ {safetyInfo.contacts?.length || 0} contacts loaded</span>
                      <span className="pill pill-cyan">🕐 24/7 Available</span>
                    </div>
                    <div style={{ fontSize: '0.85rem', color: 'var(--text-secondary)', lineHeight: 1.6 }}>
                      Area assessed as safe for tourists. Standard travel precautions recommended.
                    </div>
                  </div>
                )}
              </div>

              <div className="space-y-4">
                <div className="card" style={{ background: 'rgba(245,158,11,0.05)', borderColor: 'rgba(245,158,11,0.25)' }}>
                  <h3 style={{ fontWeight: 700, fontSize: '1rem', color: '#fbbf24', marginBottom: 16 }}>⚠️ Safety Tips</h3>
                  <div className="space-y-3">
                    {[
                      { tip: 'Keep digital and physical copies of documents', icon: '📄' },
                      { tip: 'Use registered taxis and ride-sharing apps', icon: '🚗' },
                      { tip: 'Avoid displaying valuables in crowded areas', icon: '💎' },
                      { tip: 'Share your itinerary with someone you trust', icon: '📲' },
                      { tip: 'Stay hydrated — carry water especially in summer', icon: '💧' },
                      { tip: 'Trust your instincts and stay alert', icon: '🧠' },
                    ].map((t, i) => (
                      <div key={i} style={{ display: 'flex', gap: 10, alignItems: 'flex-start', padding: '8px 0', borderBottom: i < 5 ? '1px solid var(--border)' : 'none' }}>
                        <span style={{ fontSize: '1rem', lineHeight: 1.5, flexShrink: 0 }}>{t.icon}</span>
                        <span style={{ fontSize: '0.875rem', color: 'var(--text-secondary)', lineHeight: 1.5 }}>{t.tip}</span>
                      </div>
                    ))}
                  </div>
                </div>

                <div className="card" style={{ background: 'rgba(16,185,129,0.05)', borderColor: 'rgba(16,185,129,0.25)' }}>
                  <h3 style={{ fontWeight: 700, fontSize: '1rem', color: '#34d399', marginBottom: 16 }}>🏥 Health Tips</h3>
                  <div className="space-y-3">
                    {[
                      { tip: 'Drink only bottled or purified water', icon: '🚰' },
                      { tip: 'Apply sunscreen SPF 30+ — Kerala sun is strong', icon: '☀️' },
                      { tip: 'Carry basic medications and a first-aid kit', icon: '💊' },
                      { tip: 'Travel insurance is strongly recommended', icon: '🛡️' },
                    ].map((t, i) => (
                      <div key={i} style={{ display: 'flex', gap: 10, alignItems: 'flex-start', padding: '8px 0', borderBottom: i < 3 ? '1px solid var(--border)' : 'none' }}>
                        <span style={{ fontSize: '1rem', lineHeight: 1.5, flexShrink: 0 }}>{t.icon}</span>
                        <span style={{ fontSize: '0.875rem', color: 'var(--text-secondary)', lineHeight: 1.5 }}>{t.tip}</span>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* ══════════ TRANSLATE ══════════ */}
        {activeTab === 'translate' && (
          <div className="animate-fade-up">
            <div className="flex-between mb-6" style={{ flexWrap: 'wrap', gap: 12 }}>
              <div>
                <h2 className="section-title">🌐 Translation</h2>
                <p className="section-subtitle" style={{ marginBottom: 0 }}>Real-time language assistance for your journey</p>
              </div>
              <button onClick={translateText} disabled={loading} className="btn-purple">
                {loading ? <><span className="spinner" style={{ width: 14, height: 14 }} /> Translating...</> : '🔤 Translate Sample'}
              </button>
            </div>

            {translation && (
              <div className="grid-2 mb-8">
                <div className="translate-box">
                  <div style={{ display: 'flex', gap: 8, alignItems: 'center', marginBottom: 12 }}>
                    <span className="pill pill-blue">🇬🇧 English</span>
                  </div>
                  <p style={{ fontSize: '1.05rem', color: 'var(--text-primary)', lineHeight: 1.6, fontStyle: 'italic' }}>
                    "{translation.originalText}"
                  </p>
                </div>
                <div className="translate-box" style={{ borderColor: 'rgba(139,92,246,0.3)', background: 'rgba(139,92,246,0.05)' }}>
                  <div style={{ display: 'flex', gap: 8, alignItems: 'center', marginBottom: 12 }}>
                    <span className="pill pill-purple">🇮🇳 Hindi</span>
                    <span className="pill pill-green">{Math.round((translation.confidence || 0.95) * 100)}% confidence</span>
                  </div>
                  <p style={{ fontSize: '1.05rem', color: 'var(--text-primary)', lineHeight: 1.6, fontStyle: 'italic' }}>
                    "{translation.translatedText}"
                  </p>
                </div>
              </div>
            )}

            <h3 style={{ fontWeight: 700, fontSize: '1.05rem', color: 'var(--text-primary)', marginBottom: 20 }}>
              📚 Common Travel Phrases
            </h3>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(240px, 1fr))', gap: 12 }}>
              {[
                { en: 'Hello / Greetings', hi: 'नमस्ते', ml: 'നമസ്കാരം' },
                { en: 'Thank You', hi: 'धन्यवाद', ml: 'ധന്യവാദം' },
                { en: 'How much does this cost?', hi: 'यह कितने का है?', ml: 'ഇത് എത്ര?' },
                { en: 'Where is the hospital?', hi: 'अस्पताल कहाँ है?', ml: 'ആശുപത്രി എവിടെ?' },
                { en: 'I need help', hi: 'मुझे मदद चाहिए', ml: 'എനിക്ക് സഹായം' },
                { en: 'Good Morning', hi: 'सुप्रभात', ml: 'ശുഭ പ്രഭാതം' },
                { en: 'Good Night', hi: 'शुभ रात्रि', ml: 'ശുഭ രാത്രി' },
                { en: 'Do you speak English?', hi: 'क्या आप अंग्रेजी बोलते हैं?', ml: 'നിങ്ങൾ ഇംഗ്ലീഷ് സംസാരിക്കുമോ?' },
                { en: 'Please call the police', hi: 'कृपया पुलिस को बुलाओ', ml: 'ദയവായി പോലീസിനെ വിളിക്കൂ' },
              ].map((p, i) => (
                <div key={i} className="phrase-card">
                  <div style={{ fontWeight: 700, fontSize: '0.9rem', color: 'var(--text-primary)', marginBottom: 8 }}>{p.en}</div>
                  <div style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', marginBottom: 4 }}>
                    <span style={{ color: 'var(--text-muted)' }}>Hindi: </span>{p.hi}
                  </div>
                  <div style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>
                    <span style={{ color: 'var(--text-muted)' }}>Malayalam: </span>{p.ml}
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* ══════════ MAP ══════════ */}
        {activeTab === 'map' && (
          <div className="animate-fade-up">
            <h2 className="section-title">🗺️ Map Explorer</h2>
            <p className="section-subtitle">Discover hotels, restaurants and places of interest near you</p>
            <div className="map-container-wrapper">
              <Map />
            </div>
          </div>
        )}

        {/* ══════════ DIRECTIONS ══════════ */}
        {activeTab === 'directions' && (
          <div className="animate-fade-up">
            <h2 className="section-title">🧭 Directions</h2>
            <p className="section-subtitle">Turn-by-turn route planning between any two points</p>
            <div className="card" style={{ padding: 0, overflow: 'hidden' }}>
              <DirectionsPanel />
            </div>
          </div>
        )}
      </main>

      {/* ─── Footer ─── */}
      <footer className="footer">
        <div className="footer-inner">
          <div className="footer-grid">
            <div>
              <div className="logo-mark" style={{ marginBottom: 8 }}>SmartTour</div>
              <p className="footer-brand-desc">
                Your AI-powered travel companion for Kerala and beyond. Intelligent itineraries, expert guides, real-time assistance.
              </p>
            </div>
            <div>
              <div className="footer-heading">Features</div>
              <a className="footer-link" href="#">Smart Itineraries</a>
              <a className="footer-link" href="#">Food Recommendations</a>
              <a className="footer-link" href="#">Guide Matching</a>
              <a className="footer-link" href="#">Weather Forecasting</a>
            </div>
            <div>
              <div className="footer-heading">Safety</div>
              <a className="footer-link" href="#">Emergency Contacts</a>
              <a className="footer-link" href="#">Location Safety</a>
              <a className="footer-link" href="#">Health Tips</a>
              <a className="footer-link" href="#">24/7 Support</a>
            </div>
            <div>
              <div className="footer-heading">Tools</div>
              <a className="footer-link" href="#">Translation</a>
              <a className="footer-link" href="#">Map Explorer</a>
              <a className="footer-link" href="#">Route Planner</a>
              <a className="footer-link" href="#">Weather API</a>
            </div>
          </div>
          <div className="footer-bottom">
            <span className="footer-bottom-text">© 2024 SmartTour. All rights reserved.</span>
            <span className="footer-bottom-text">Powered by Agentic AI 🤖 · Open-Meteo · OpenStreetMap · OSRM</span>
          </div>
        </div>
      </footer>
    </div>
  );
}
